# agent_utils.py
import anthropic
import json
from typing import Any, Callable
from functools import wraps
import time
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

client = anthropic.Anthropic()

class AgentRunner:
    """General-purpose agent runner"""

    def __init__(
        self,
        system_prompt: str,
        tools: list[dict],
        tool_handlers: dict[str, Callable],
        model: str = "claude-sonnet-4-6",
        max_iterations: int = 10
    ):
        self.system_prompt = system_prompt
        self.tools = tools
        self.tool_handlers = tool_handlers
        self.model = model
        self.max_iterations = max_iterations
        self.messages = []

    def run(self, user_input: str) -> str:
        """Run the agent and return the final answer"""
        self.messages.append({"role": "user", "content": user_input})

        for iteration in range(self.max_iterations):
            logger.info(f"Iteration {iteration + 1}/{self.max_iterations}")

            response = client.messages.create(
                model=self.model,
                max_tokens=4096,
                system=self.system_prompt,
                tools=self.tools,
                messages=self.messages
            )

            if response.stop_reason == "end_turn":
                final_text = "".join(
                    block.text for block in response.content
                    if hasattr(block, 'text')
                )
                return final_text

            if response.stop_reason == "tool_use":
                self.messages.append({
                    "role": "assistant",
                    "content": response.content
                })

                tool_results = []
                for block in response.content:
                    if block.type == "tool_use":
                        logger.info(f"Tool called: {block.name}")
                        try:
                            handler = self.tool_handlers.get(block.name)
                            if not handler:
                                raise ValueError(f"No handler for tool: {block.name}")
                            result = handler(**block.input)
                            tool_results.append({
                                "type": "tool_result",
                                "tool_use_id": block.id,
                                "content": json.dumps(result, ensure_ascii=False)
                            })
                        except Exception as e:
                            tool_results.append({
                                "type": "tool_result",
                                "tool_use_id": block.id,
                                "content": f"Error: {str(e)}",
                                "is_error": True
                            })

                self.messages.append({
                    "role": "user",
                    "content": tool_results
                })

        return "Maximum number of iterations reached."

    def reset(self):
        """Reset conversation history"""
        self.messages = []


def retry_with_backoff(max_retries: int = 3, base_delay: float = 1.0):
    """Decorator that retries with exponential backoff"""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(max_retries):
                try:
                    return func(*args, **kwargs)
                except anthropic.RateLimitError:
                    if attempt == max_retries - 1:
                        raise
                    delay = base_delay * (2 ** attempt)
                    logger.warning(f"Rate limited. Waiting {delay}s...")
                    time.sleep(delay)
            return None
        return wrapper
    return decorator
